import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { appActions, breadCrumbActions, errorNotice, headerActions, headerStrings, HighlightedInfo, hirUtil, history, monthSelections, MyDialog, MyTable, SimplePagination, simplePaginationConfig, StageHeaderPlane } from '../utils';
import { hirRouteNames } from '../routeNames';
import { HIRButton, HIRStartEndDates } from '../Includes';
import { Add, CalendarToday, CalendarViewDay, Delete, Edit } from '@material-ui/icons';
import { HIRFindPatient } from '../HIRPatients';
import { HIRNewDeposit } from './HIRNewDeposit';
import { hirAccountActions } from '../HIRAccounts';
import { Button, Checkbox, FormControlLabel, IconButton, TableCell, Typography } from '@material-ui/core';
import Calendar from 'react-calendar';
import exportFromJSON from 'export-from-json'


const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    iconBtn : {
        padding : 3 
    },
    headerContainer : {
        display : 'flex',
        marginBottom : 20,
        alignItems : "center",
    },
    total : {
        display : "flex", 
        justifyContent : "center", 
        alignItems : "center",
        color : "white",
        backgroundColor : theme.colors.primary1,
        borderRadius : 20,
        fontSize : 14,
        fontWeight : "bold",
        padding : 10
    },
    dialogDateContainer : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center"
    },
    download : {
        fontSize : 12,
        textDecoration : "underline",
        "&:hover" : {
            cursor : "pointer",
        }
    }
})
class _HIRDeposits extends Component {
    constructor(props) {
        super(props);
        this.state = {
            dialogType : "date",
            openDialog : false,
            filter : {
                monthOnly : false,
                startDate : null,
                endDate : null,
                date : new Date(),
            }
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "Desposits",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Deposits", pathname : hirRouteNames.patients}
        ])(dispatch);
    }
    componentDidMount() {
        this.depositConfig();
    }
    
    searchAction(keyword){
        this.pageControl.search(keyword);
    }
    newButton(){
        return <HIRButton
            onClick={()=>this.setState({openDialog : true, dialogType : "patient"})}
        >
            <Add fontSize="small"/> 
            New Deposit
        </HIRButton>
    }
    searchPatientRowAction = row => () => {
        this.setState({
            dialogType : "deposit",
            patient : row
        })
    }
    closeDialog = () => this.setState({openDialog : false, dialogType : "", patient : null, deposit : null});
    onUpdateDeposit(data, callback) {
        const {dispatch} = this.props,
        {deposit} = this.state,
        {_id : depositId} = deposit || {};
        if(!depositId) return errorNotice("There is no patient selected", dispatch);
        hirAccountActions.updateDeposit(depositId, data, done => {
            callback && callback(done);
            if(done){
                this.depositConfig();
                this.closeDialog();
            }
        })(dispatch);
    }
    createDeposit(data, callback) {
        const {dispatch} = this.props,
        {patient} = this.state,
        patientId = patient && patient._id;
        if(!patientId) return errorNotice("There is no patient selected", dispatch);
        hirAccountActions.createDeposit({...data, patientId}, done => {
            callback && callback(done);
            if(done){
                this.depositConfig();
                this.closeDialog();
            }
        })(dispatch);
    }
    deleteDeposit(deposit){
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Sure! You want to delete this deposit? This will affect accounts",
            [<Button key="deleteDeposit" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                hirAccountActions.deleteDeposit(deposit && deposit._id, done => {
                    if(done){
                        this.closeDialog();
                        this.depositConfig();
                    }
                })(dispatch);
            }}>Continue</Button>]
        )(dispatch);
    }
    depositConfig(callback){
        this.pageControl = simplePaginationConfig(
            this, this.getDeposits, this.props.dispatch,
            "deposits", 50, null, null, this.getDepositMinMaxIds,
            this.searchDeposits, this.getSearchDepositMinMaxIds
        )
        this.setState({keyword : ""});
        this.pageControl.getAction(callback);
    }
    getFilter(){
        const {filter} = this.state;
        return {...filter, detail : true};
    }
    getDeposits = (rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getDeposits(filter, rows, skip, sort, max, callback)(dispatch);
    }
    getDepositMinMaxIds = (sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getDepositMinMaxIds(filter, sort, callback)(dispatch);
    }
    searchDeposits = (keyword, rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.searchDeposits(filter, keyword, rows, skip, sort, max, callback)(dispatch);
    }
    getSearchDepositMinMaxIds = (keyword, sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirAccountActions.getSearchDepositMinMaxIds(filter, keyword, sort, callback)(dispatch);
    }
    veiwPatient = patientId => e => {
        e.stopPropagation();
        history.push(hirRouteNames.patientView_+patientId);
    }
    cellMapFormat({row, cellMap}){
        const {classes} = this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                {hirUtil.isAdmin() && <div>
                    <IconButton className={classes.iconBtn}
                        onClick={()=>this.setState({openDialog : true, dialogType : "deposit", deposit : row})}
                    >
                        <Edit fontSize="small"/>
                    </IconButton>
                    <IconButton className={classes.iconBtn}
                        onClick={()=>this.deleteDeposit(row)}
                    >
                        <Delete fontSize="small" color="secondary"/>
                    </IconButton>
                </div>}
            </TableCell>
            case "actionDate" : return <TableCell className={classes.cell}>
                {new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {hirUtil._id(row[cellMap])}
            </TableCell>
            case "name" : 
                const {_id : patientId, myProfile} = row.patient || {},
                {lastName, firstName} = myProfile || {},
                name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                return <TableCell className={classes.cell}>
                    <u className={classes.cellName}
                        onClick={this.veiwPatient(patientId)}>
                        {name}
                    </u>
                </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    changeFilter = name => (e) => {
        const value = e.target.checked;
        this.setState({filter : {...this.state.filter, [name] : value}}, ()=>{
            this.depositConfig();
        });
    }
    header = ["ID", "Patient", "Deposit", "Description", "Date", "Actions"];
    headerMapper = ["_id", "name", "amount", "description", "actionDate", "action"];
    dateSearchBtn(){
        const {dateSearchLoading} = this.state;
        return <div style={{marginTop : 20}}>
            <HIRButton type="primary" 
                loading={dateSearchLoading}
                onClick={()=>{
                    this.closeDialog();
                    this.depositConfig()
                }}>
                    Get Deposits
                </HIRButton>
        </div>
    }
    downloadCVS(data){
        const {dispatch} = this.props,
        fileName = 'deposits',
        exportType = 'csv',
        mainData = []
        if(data) for (let i = 0; i < data.length; i++) {
            const dataObject = data[i],
            mainD = {},
            {myProfile} = dataObject?.patient || {};
            for (let j = 0; j < this.headerMapper.length; j++) {
                const mapper = this.headerMapper[j];
                let value = dataObject[mapper],
                header = this.header[j];
                switch(mapper){
                    case "actionDate" : 
                        mainD[header] = value && new Date(value).toLocaleDateString(); 
                        break;
                    case "amount" : 
                        mainD[header] = value && new Number(value).toLocaleString(); 
                        break;
                    case "_id" : 
                        mainD[header] = dataObject?.patient?._id;
                        break;
                    case "actionDate" : 
                        mainD[header] = new Date(value).toLocaleDateString();
                        break;
                    case "name" : 
                        const {lastName, firstName} = myProfile || {},
                        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                        mainD[header] = name;
                        break;
                    default: mainD[header] = dataObject[mapper]; break;
                }
            }
            mainData.push(mainD);
        }
        appActions.showSnackDialog(
            "You are about to download a CSV file. Do you want to continue?",
            [<Button key="downloadCSV" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                exportFromJSON({ data : mainData, fileName, exportType })
            }}>Continue</Button>]
        )(dispatch);
    }
    render() {
        const {classes} = this.props,
        {openDialog, dialogType, patient, deposits, deposit, filter} = this.state,
        {myProfile} = patient || {},
        {monthOnly, date, startDate, endDate} = filter || {},
        {lastName, firstName} = myProfile || {},
        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
        let total = 0;
        if(deposits) for (let i = 0; i < deposits.length; i++) {
            const {amount} = deposits[i];
            total += amount;
        }
        return (
            <div className={classes.root}>
                <HighlightedInfo>
                    Note: Once part of a deposit is used or the remaining patient's credit is not up to a deposit, such deposit can't be deleted or refunded!
                </HighlightedInfo>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        refreshCallback={()=>this.setState({filter : {}}, this.depositConfig.bind(this))}
                        // onChangeCallback={this.searchOnChangeCallback.bind(this)}
                        searchActions={this.searchAction.bind(this)}
                        components={[this.newButton.bind(this)]}
                        />
                </div>
                <div className={classes.headerContainer}>
                    <IconButton onClick={()=>this.setState({openDialog : true, dialogType : "date"})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnly}
                            onChange={this.changeFilter("monthOnly")}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                        />
                    {hirUtil.isAdmin() && <div><HIRButton
                        type="secondary"
                        onClick={()=>this.setState({openDialog : true, dialogType : "dateRange"})}
                        classes={{btn : classes.marginRight}}
                        >
                            <CalendarViewDay fontSize="small"/>
                            Date Range
                    </HIRButton></div>}
                    <div style={{display : "flex", flexGrow : 1}}/>
                    <div className={classes.total}>
                        Total : N{Number(total).toLocaleString()}
                    </div>
                </div>
                
                <div style={{marginTop : 20}}>
                    <MyTable
                        title={<small>{dialogType === "date" ? 
                            (monthOnly ? 
                                date.getFullYear()+", "+(monthSelections.find(item=>item.value ==date.getMonth()+1).name) : 
                                date.toDateString()
                            )  : new Date(startDate).toLocaleDateString() + " to " + 
                            new Date(endDate).toLocaleDateString()}
                            </small>}
                        header={this.header}
                        dataMap={this.headerMapper}
                        CellMap={this.cellMapFormat.bind(this)}
                        data={deposits}
                        />
                    {this.pageControl && <div style={{marginTop : 20}}>
                        <SimplePagination
                            nextBtnClick={this.pageControl.nextBtnOnClick()}
                            nextBtnProps={{
                                disabled : this.pageControl.nextBtnDisabled()
                            }}
                            prevBtnClick={this.pageControl.prevBtnOnClick()}
                            prevBtnProps={{
                                disabled : this.pageControl.prevBtnDisabled()
                            }}
                            />
                    </div>}
                    <div style={{display : "flex", justifyContent : "flex-end", paddingBottom : 20}}>
                        <a onClick={()=>this.downloadCVS(deposits)} className={classes.download}>
                            Download CSV file
                        </a>
                    </div>
                </div>
                <MyDialog 
                    within
                    open={openDialog}
                    close={this.closeDialog.bind(this)}
                >
                    <div className={classes.dialogContainer}>
                        {dialogType === "patient" && <HIRFindPatient
                            patientListProps={{
                                tableProps : {
                                    rowAction : this.searchPatientRowAction.bind(this)
                                }
                            }}
                        />}
                        {dialogType == "deposit" && <HIRNewDeposit
                            title={"Deposit for " + name}
                            onCreateDeposit={this.createDeposit.bind(this)}
                            data={deposit}
                            onCancel={this.closeDialog.bind(this)}
                            onEdit={Boolean(deposit)}
                            onUpdateDeposit={this.onUpdateDeposit.bind(this)}
                        />}
                        <div className={classes.dialogDateContainer}>
                            {dialogType === "date" && <Fragment>
                                    <Typography paragraph className={classes.header}>Search Deposit by dates</Typography>
                                <Calendar
                                    value={date}
                                    onChange={date=>this.setState(state=>({filter : {
                                        ...state.filter, date, startDate : null, endDate : null
                                    }}))}/>
                                {this.dateSearchBtn()}
                            </Fragment>}
                            {dialogType === "dateRange" && <Fragment>
                                <Typography paragraph className={classes.header}>Search Deposit by dates range</Typography>
                                <HIRStartEndDates
                                    noTitle
                                    containerProps={{
                                        style : {
                                            width : "100%"
                                        }
                                    }}
                                    onDateChange={(startDate, endDate)=>this.setState(state=>({
                                        filter : {...state.filter, startDate, endDate, date : null}
                                    }))}/>
                                {this.dateSearchBtn()}
                            </Fragment>}
                        </div>
                    </div>
                </MyDialog>
            </div>
        );
    }
}


_HIRDeposits.propTypes = {
    classes : PropTypes.object.isRequired,
};
const mapStateToProps = state => ({
    state
})


export const HIRDeposits = connect(mapStateToProps)(withStyles(style)(_HIRDeposits));
export {HIRDeposits as default}